import { useState, useRef, useEffect } from "react";
import API from "../services/api";

function ChatBox() {
  const [messages, setMessages] = useState([
    {
      id: 1,
      type: "bot",
      text: "👋 Hello! I'm your Cricket Stats Assistant. I can help you find player statistics, match results, team performance, and more. What would you like to know?"
    }
  ]);
  const [inputValue, setInputValue] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const sendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMessage = inputValue.trim();
    setInputValue("");

    const userMessageId = Date.now();
    setMessages(prev => [...prev, {
      id: userMessageId,
      type: "user",
      text: userMessage
    }]);

    setLoading(true);

    const botMessageId = Date.now() + 1;
    setMessages(prev => [...prev, {
      id: botMessageId,
      type: "bot",
      text: "",
      loading: true
    }]);

    try {
      const userInfo = JSON.parse(localStorage.getItem("userInfo"));
      const token = userInfo?.token;

      const response = await fetch(`${process.env.REACT_APP_API_URL || "http://localhost:5000/api"}/chat/stream`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`
        },
        body: JSON.stringify({ message: userMessage })
      });

      if (!response.ok) throw new Error("Network response was not ok");

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let botResponse = "";

      setLoading(false);

      while (true) {
        const { value, done } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value);
        const lines = chunk.split("\n\n");

        for (const line of lines) {
          if (line.startsWith("data: ")) {
            try {
              const data = JSON.parse(line.substring(6));
              if (data.type === "done") break;
              if (data.text) {
                botResponse += data.text;
                setMessages(prev => prev.map(msg => 
                  msg.id === botMessageId ? { ...msg, text: botResponse, loading: false } : msg
                ));
              }
            } catch (e) {
              console.error("Error parsing JSON chunk", e);
            }
          }
        }
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => prev.map(msg => 
        msg.id === botMessageId ? { 
          ...msg, 
          text: "❌ Error: Unable to get response. Please try again.", 
          isError: true,
          loading: false 
        } : msg
      ));
    } finally {
      setLoading(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const quickQuestions = [
    "Show Virat Kohli stats",
    "India vs Pakistan results",
    "List all teams",
    "Top performers",
    "Match statistics"
  ];

  return (
    <div style={{
      display: "flex",
      flexDirection: "column",
      height: "100%",
      maxWidth: "900px",
      margin: "0 auto",
      backgroundColor: "#121212",
      borderRadius: "16px",
      boxShadow: "0 8px 32px rgba(0,0,0,0.4)",
      overflow: "hidden",
      border: "1px solid #333",
      fontFamily: "'Segoe UI', Roboto, Helvetica, Arial, sans-serif"
    }}>
      {/* Header */}
      <div style={{
        padding: "20px",
        background: "linear-gradient(135deg, #1e1e1e 0%, #121212 100%)",
        color: "#00ff88",
        textAlign: "center",
        borderBottom: "1px solid #333"
      }}>
        <h2 style={{ margin: "0", fontSize: "22px", fontWeight: "700", letterSpacing: "1px" }}>
          🏏 CRICKET AI ASSISTANT
        </h2>
        <p style={{ margin: "5px 0 0 0", fontSize: "13px", color: "#888" }}>Powered by Gemini Flash for lightning-fast stats</p>
      </div>

      {/* Messages Area */}
      <div style={{
        flex: 1,
        overflowY: "auto",
        padding: "20px",
        backgroundColor: "#181818",
        display: "flex",
        flexDirection: "column",
        gap: "16px"
      }}>
        {messages.map(msg => (
          <div
            key={msg.id}
            style={{
              display: "flex",
              justifyContent: msg.type === "user" ? "flex-end" : "flex-start",
              width: "100%"
            }}
          >
            <div style={{
              maxWidth: "80%",
              padding: "14px 18px",
              borderRadius: msg.type === "user" ? "18px 18px 2px 18px" : "18px 18px 18px 2px",
              backgroundColor: msg.type === "user" ? "#00c853" : (msg.isError ? "#ff5252" : "#2a2a2a"),
              color: msg.type === "user" ? "#000" : "#e0e0e0",
              wordWrap: "break-word",
              whiteSpace: "pre-wrap",
              fontSize: "15px",
              lineHeight: "1.5",
              boxShadow: "0 2px 5px rgba(0,0,0,0.2)",
              fontWeight: msg.type === "user" ? "600" : "400",
              border: msg.type === "bot" ? "1px solid #333" : "none"
            }}>
              {msg.loading ? (
                <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                  <div className="typing-indicator">
                    <span></span>
                    <span></span>
                    <span></span>
                  </div>
                  <span style={{ fontSize: "12px", color: "#aaa" }}>Analyzing stats...</span>
                </div>
              ) : msg.text}
            </div>
          </div>
        ))}

        <div ref={messagesEndRef} />
      </div>

      {/* Quick Questions */}
      {messages.length === 1 && (
        <div style={{
          padding: "15px 20px",
          backgroundColor: "#1e1e1e",
          borderTop: "1px solid #333"
        }}>
          <p style={{ margin: "0 0 12px 0", fontSize: "13px", color: "#00ff88", fontWeight: "600" }}>
            QUICK STATS:
          </p>
          <div style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "10px"
          }}>
            {quickQuestions.map((question, idx) => (
              <button
                key={idx}
                onClick={() => {
                  setInputValue(question);
                  // Trigger send if user clicks
                  const fakeEvent = { preventDefault: () => {}, key: 'Enter', shiftKey: false };
                  setTimeout(() => sendMessage(question), 0);
                }}
                style={{
                  padding: "8px 16px",
                  backgroundColor: "#2a2a2a",
                  border: "1px solid #444",
                  color: "#e0e0e0",
                  borderRadius: "20px",
                  cursor: "pointer",
                  fontSize: "13px",
                  transition: "all 0.3s ease"
                }}
                onMouseOver={(e) => {
                  e.target.style.borderColor = "#00ff88";
                  e.target.style.backgroundColor = "#1e1e1e";
                  e.target.style.color = "#00ff88";
                }}
                onMouseOut={(e) => {
                  e.target.style.borderColor = "#444";
                  e.target.style.backgroundColor = "#2a2a2a";
                  e.target.style.color = "#e0e0e0";
                }}
              >
                {question}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Input Area */}
      <div style={{
        padding: "20px",
        backgroundColor: "#121212",
        borderTop: "1px solid #333",
        display: "flex",
        gap: "12px",
        alignItems: "flex-end"
      }}>
        <textarea
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onKeyPress={handleKeyPress}
          placeholder="Type your cricket query here..."
          disabled={loading}
          style={{
            flex: 1,
            padding: "12px 16px",
            backgroundColor: "#222",
            border: "1px solid #444",
            borderRadius: "12px",
            color: "#fff",
            fontFamily: "inherit",
            fontSize: "15px",
            resize: "none",
            maxHeight: "120px",
            minHeight: "48px",
            outline: "none",
            transition: "border-color 0.2s"
          }}
          onFocus={(e) => e.target.style.borderColor = "#00ff88"}
          onBlur={(e) => e.target.style.borderColor = "#444"}
        />
        <button
          onClick={() => sendMessage()}
          disabled={loading || !inputValue.trim()}
          style={{
            height: "48px",
            width: "48px",
            backgroundColor: loading || !inputValue.trim() ? "#333" : "#00c853",
            color: loading || !inputValue.trim() ? "#666" : "#000",
            border: "none",
            borderRadius: "12px",
            cursor: loading || !inputValue.trim() ? "not-allowed" : "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            transition: "transform 0.2s, background-color 0.2s",
            fontSize: "20px"
          }}
          onMouseOver={(e) => {
            if (!loading && inputValue.trim()) {
              e.target.style.transform = "scale(1.05)";
              e.target.style.backgroundColor = "#00e676";
            }
          }}
          onMouseOut={(e) => {
            e.target.style.transform = "scale(1)";
            if (!loading && inputValue.trim()) {
              e.target.style.backgroundColor = "#00c853";
            }
          }}
        >
          {loading ? "⏳" : "✈️"}
        </button>
      </div>
    </div>
  );
}

export default ChatBox;
